package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.BeforeEach;
import org.mockito.Mockito;

class CSVFormatTest {

    private CSVFormat csvFormatDefault;
    private CSVFormat csvFormatCustom;

    @BeforeEach
    void setUp() {
        csvFormatDefault = CSVFormat.DEFAULT;
        csvFormatCustom = new CSVFormat(',', '"', null, null, null, false, true, "\r\n",
                null, null, null, false, false, false, false, false, false);
    }

    @Test
    void testGetDelimiter_Default() {
        assertEquals(',', csvFormatDefault.getDelimiter());
    }

    @Test
    void testGetDelimiter_CustomDelimiter() {
        CSVFormat custom = csvFormatDefault.withDelimiter('|');
        assertEquals('|', custom.getDelimiter());
    }

    @Test
    void testGetDelimiter_OtherPredefinedFormats() {
        assertEquals(',', CSVFormat.EXCEL.getDelimiter());
        assertEquals('|', CSVFormat.INFORMIX_UNLOAD.getDelimiter());
        assertEquals(',', CSVFormat.INFORMIX_UNLOAD_CSV.getDelimiter());
        assertEquals('\t', CSVFormat.MYSQL.getDelimiter());
        assertEquals(',', CSVFormat.POSTGRESQL_CSV.getDelimiter());
        assertEquals('\t', CSVFormat.POSTGRESQL_TEXT.getDelimiter());
        assertEquals(',', CSVFormat.RFC4180.getDelimiter());
        assertEquals('\t', CSVFormat.TDF.getDelimiter());
    }

    @Test
    void testGetDelimiter_NewFormatStaticFactory() {
        CSVFormat format = CSVFormat.newFormat(';');
        assertEquals(';', format.getDelimiter());
    }

    @Test
    void testGetDelimiter_WithReflection() throws Exception {
        // Using reflection to access private field 'delimiter'
        java.lang.reflect.Field delimiterField = CSVFormat.class.getDeclaredField("delimiter");
        delimiterField.setAccessible(true);
        delimiterField.set(csvFormatCustom, ':');
        assertEquals(':', csvFormatCustom.getDelimiter());
    }
}
